SELECT *
FROM cases
WHERE docket_number = 'D-789012';

SELECT defendants.name, defendants.case_id
FROM defendants
INNER JOIN cases ON defendants.case_id = cases.case_id;

SELECT DISTINCT case_id
FROM defendants
WHERE criminal_history_id IS NOT NULL;

SELECT name, age, address
FROM defendants
ORDER BY age DESC;

SELECT COUNT(*)
FROM case_notes
WHERE note_type = 'hearing note' AND note_date >= '2023-01-01';

SELECT COUNT(*)
FROM defendants
WHERE age < 18;
